"""
详细面板窗口 - 浅色主题 · 卡片式统计 · 并排热力图
"""
from PyQt5.QtWidgets import (
    QWidget, QVBoxLayout, QHBoxLayout, QLabel,
    QTableWidget, QTableWidgetItem, QHeaderView, QFrame,
    QSplitter, QGridLayout, QScrollArea
)
from PyQt5.QtCore import Qt, QTimer
from PyQt5.QtGui import QFont, QPalette, QColor
from datetime import date
import config
from keyboard_heatmap import KeyboardHeatmap


# ── 浅色主题 QSS ──────────────────────────────────────────

STYLESHEET = """
/* 全局 */
QWidget {
    background-color: #F0F2F5;
    font-family: "Segoe UI", "Noto Sans", "Ubuntu", sans-serif;
    color: #1E293B;
}

/* 滚动条整体 */
QScrollBar:vertical {
    background: transparent;
    width: 6px;
    margin: 0;
}
QScrollBar::handle:vertical {
    background: #CBD5E1;
    border-radius: 3px;
    min-height: 20px;
}
QScrollBar::handle:vertical:hover {
    background: #94A3B8;
}
QScrollBar::add-line:vertical, QScrollBar::sub-line:vertical {
    height: 0px;
}

QScrollBar:horizontal {
    background: transparent;
    height: 6px;
}
QScrollBar::handle:horizontal {
    background: #CBD5E1;
    border-radius: 3px;
    min-width: 20px;
}
QScrollBar::add-line:horizontal, QScrollBar::sub-line:horizontal {
    width: 0px;
}

/* 按钮 */
QPushButton {
    background: #FFFFFF;
    border: 1px solid #E2E8F0;
    border-radius: 6px;
    padding: 4px 12px;
    color: #475569;
    font-size: 12px;
}
QPushButton:hover {
    background: #F8FAFC;
    border-color: #3B82F6;
    color: #3B82F6;
}
QPushButton:checked {
    background: #3B82F6;
    border-color: #3B82F6;
    color: white;
}
QPushButton:pressed {
    background: #2563EB;
}

/* 表格 */
QTableWidget {
    background: #FFFFFF;
    border: 1px solid #E2E8F0;
    border-radius: 8px;
    gridline-color: #F1F5F9;
    font-size: 12px;
}
QTableWidget::item {
    padding: 4px 8px;
}
QTableWidget::item:selected {
    background: #EFF6FF;
    color: #1E293B;
}
QHeaderView::section {
    background: #F8FAFC;
    border: none;
    border-bottom: 2px solid #E2E8F0;
    padding: 6px 8px;
    font-weight: bold;
    font-size: 12px;
    color: #64748B;
}

/* 分隔线 */
QFrame[frameShape="4"] {  /* HLine */
    color: #E2E8F0;
}

/* 卡片区域 */
QFrame#statCard {
    background: #FFFFFF;
    border: 1px solid #E2E8F0;
    border-radius: 10px;
}
QFrame#statCard:hover {
    border-color: #93C5FD;
}

/* 分割条手柄 */
QSplitter::handle {
    background: #E2E8F0;
}
QSplitter::handle:hover {
    background: #3B82F6;
}
"""


class StatCard(QFrame):
    """单个统计卡片"""

    def __init__(self, label: str, default_value: str, parent=None):
        super().__init__(parent)
        self.setObjectName("statCard")
        self.setMinimumSize(130, 72)

        layout = QVBoxLayout(self)
        layout.setContentsMargins(14, 10, 14, 10)
        layout.setSpacing(2)

        self.label = QLabel(label)
        self.label.setStyleSheet("color: #64748B; font-size: 12px;")

        self.value = QLabel(default_value)
        self.value.setStyleSheet("color: #1E293B; font-size: 20px; font-weight: bold;")

        layout.addWidget(self.label)
        layout.addWidget(self.value)

    def set_value(self, text: str):
        self.value.setText(text)


class DetailWindow(QWidget):
    """详细统计面板窗口"""

    def __init__(self, tracker, db, parent=None):
        super().__init__(parent)
        self.tracker = tracker
        self.db = db

        self.setWindowTitle(f"{config.APP_NAME}")
        self.setMinimumSize(950, 520)
        self.setWindowFlags(Qt.Window | Qt.WindowCloseButtonHint | Qt.WindowStaysOnTopHint)

        self.setStyleSheet(STYLESHEET)

        self._init_ui()

        self.timer = QTimer(self)
        self.timer.timeout.connect(self._update_display)
        self.timer.start(1000)

        self._update_display()

    def _init_ui(self):
        main_layout = QHBoxLayout(self)
        main_layout.setContentsMargins(0, 0, 0, 0)
        main_layout.setSpacing(0)

        splitter = QSplitter(Qt.Horizontal)
        splitter.setHandleWidth(3)
        splitter.setStyleSheet("QSplitter::handle { background: #E2E8F0; }")

        # ═══ 左侧面板 ═══
        left = QWidget()
        left_layout = QVBoxLayout(left)
        left_layout.setContentsMargins(18, 14, 12, 14)
        left_layout.setSpacing(10)

        # 标题
        title = QLabel("今日统计")
        title.setStyleSheet("font-size: 18px; font-weight: bold; color: #0F172A;")
        title.setAlignment(Qt.AlignCenter)
        left_layout.addWidget(title)

        self.date_label = QLabel(date.today().isoformat())
        self.date_label.setAlignment(Qt.AlignCenter)
        self.date_label.setStyleSheet("color: #94A3B8; font-size: 13px;")
        left_layout.addWidget(self.date_label)

        # 细分隔线
        left_layout.addWidget(self._create_separator())

        # 2×3 卡片网格
        card_grid = QGridLayout()
        card_grid.setSpacing(10)

        self.cards = {}
        card_items = [
            ('keyboard', '键盘敲击', '0 次'),
            ('left_click', '鼠标左键', '0 次'),
            ('right_click', '鼠标右键', '0 次'),
            ('move', '鼠标移动', '0 cm'),
            ('scroll', '滚动距离', '0'),
        ]

        for i, (key, label, default) in enumerate(card_items):
            card = StatCard(label, default)
            self.cards[key] = card
            row, col = divmod(i, 2)
            card_grid.addWidget(card, row, col)

        left_layout.addLayout(card_grid)

        # 历史区域
        left_layout.addWidget(self._create_separator())

        history_title = QLabel("最近7天历史")
        history_title.setStyleSheet("font-size: 13px; font-weight: bold; color: #334155;")
        left_layout.addWidget(history_title)

        self.history_table = QTableWidget()
        self.history_table.setColumnCount(4)
        self.history_table.setHorizontalHeaderLabels(['日期', '键盘', '左键', '右键'])
        self.history_table.horizontalHeader().setSectionResizeMode(QHeaderView.Stretch)
        self.history_table.setEditTriggers(QTableWidget.NoEditTriggers)
        self.history_table.setSelectionBehavior(QTableWidget.SelectRows)
        self.history_table.setMaximumHeight(180)
        self.history_table.verticalHeader().setVisible(False)
        left_layout.addWidget(self.history_table)

        left_layout.addStretch()

        # ═══ 右侧面板 ═══
        right = QWidget()
        right_layout = QVBoxLayout(right)
        right_layout.setContentsMargins(4, 4, 10, 4)
        right_layout.setSpacing(4)

        right_title = QLabel("键盘热力图")
        right_title.setStyleSheet("font-size: 14px; font-weight: bold; color: #334155;")
        right_title.setAlignment(Qt.AlignCenter)
        right_layout.addWidget(right_title)

        self.heatmap = KeyboardHeatmap()
        right_layout.addWidget(self.heatmap)

        # 组装
        splitter.addWidget(left)
        splitter.addWidget(right)
        splitter.setSizes([350, 600])
        splitter.setStretchFactor(0, 0)
        splitter.setStretchFactor(1, 1)

        main_layout.addWidget(splitter)

        self._update_history_table()

    def _create_separator(self) -> QFrame:
        line = QFrame()
        line.setFrameShape(QFrame.HLine)
        line.setFrameShadow(QFrame.Plain)
        line.setStyleSheet("color: #E2E8F0; max-height: 1px;")
        return line

    def _update_display(self):
        stats = self.tracker.get_stats()

        self.cards['keyboard'].set_value(f"{stats['key_presses']:,} 次")
        self.cards['left_click'].set_value(f"{stats['mouse_left_clicks']:,} 次")
        self.cards['right_click'].set_value(f"{stats['mouse_right_clicks']:,} 次")
        self.cards['move'].set_value(self._format_distance(stats['mouse_move_distance']))
        self.cards['scroll'].set_value(f"{stats['scroll_distance']:,}")

        self.date_label.setText(date.today().isoformat())

        key_detail = stats.get('key_detail', {})
        if key_detail:
            self.heatmap.set_key_stats(key_detail)

    def _format_distance(self, pixels: float) -> str:
        cm = pixels * 2.54 / 96
        if cm < 1:
            return f"{cm * 10:.1f} mm"
        return f"{cm:.1f} cm"

    def _update_history_table(self):
        history = self.db.get_history(config.HISTORY_DAYS)
        self.history_table.setRowCount(len(history))
        for i, record in enumerate(history):
            self.history_table.setItem(i, 0, QTableWidgetItem(record['date']))
            self.history_table.setItem(i, 1, QTableWidgetItem(f"{record['key_presses']:,}"))
            self.history_table.setItem(i, 2, QTableWidgetItem(f"{record['mouse_left_clicks']:,}"))
            self.history_table.setItem(i, 3, QTableWidgetItem(f"{record['mouse_right_clicks']:,}"))

    def closeEvent(self, event):
        event.ignore()
        self.hide()

